#include <bits/stdc++.h>
using namespace std;
int a[2003], dp[2003][2003], s[2003];

int main()
{
	int n;
	cin >> n;
	for(int i = 1; i <= n; i++)
		cin >> a[i];
	for(int i = 1; i <= n; i++)
		s[i] = s[i - 1] + a[i];
	for(int i = 1; i <= n; i++)
	{
		dp[i][i] = a[i];
	}
	for(int l = 2; l <= n; l++)
	{
		for(int i = 1; i <= n - l + 1; i++)
		{
			int j = i + l - 1;
			dp[i][j] = max(dp[i][j], dp[i + 1][j] + a[i] + s[j] - s[i]);
			dp[i][j] = max(dp[i][j], dp[i][j - 1] + a[j] + s[j - 1] - s[i - 1]);
		}
	}
	cout << dp[1][n];
}
